Here is the complete verbatim content of `app/(tabs)/admin/index.tsx`:

```tsx
import React, { useCallback, useEffect, useRef, useState } from 'react';
import {
  View,
  Text,
  ScrollView,
  Animated,
  Pressable,
  ActivityIndicator,
  RefreshControl,
} from 'react-native';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { useFocusEffect, useRouter } from 'expo-router';
import { Plus, Pencil, CheckCircle, Download } from 'lucide-react-native';
import { ResultsModal } from '@/components/ResultsModal';
import type { PollWithCounts } from '@/components/ResultsChart';

const BASE_URL = 'https://at52tm8me4yfm63sgxb9tx3u2csxcjqs.app.specular.dev';

const COLORS = {
  background: '#F5F0FF',
  surface: '#FFFFFF',
  purple: '#A855F7',
  purpleLight: '#F3E8FF',
  coral: '#FF6B6B',
  coralLight: '#FFE8E8',
  blue: '#4ECDC4',
  blueLight: '#E0F7F5',
  green: '#22C55E',
  greenLight: '#DCFCE7',
  yellow: '#FFD93D',
  text: '#1A1A2E',
  textSecondary: '#6B6B8A',
  border: 'rgba(26,26,46,0.08)',
};

type Poll = {
  id: string;
  title: string;
  description?: string;
  option_a_label: string;
  option_b_label: string;
  option_a_emoji: string;
  option_b_emoji: string;
  is_active: boolean;
  created_at: string;
  updated_at: string;
  collection_id?: string | null;
  counts?: { a: number; b: number; total: number };
};

type Collection = {
  id: string;
  name: string;
  color: string;
  emoji: string;
};

function MiniBarChart({ countA, countB, total }: { countA: number; countB: number; total: number }) {
  const widthA = useRef(new Animated.Value(0)).current;
  const widthB = useRef(new Animated.Value(0)).current;

  const pctA = total > 0 ? countA / total : 0;
  const pctB = total > 0 ? countB / total : 0;

  useEffect(() => {
    Animated.parallel([
      Animated.timing(widthA, { toValue: pctA, duration: 600, delay: 100, useNativeDriver: false }),
      Animated.timing(widthB, { toValue: pctB, duration: 600, delay: 200, useNativeDriver: false }),
    ]).start();
  }, [pctA, pctB]);

  const totalDisplay = total.toString();

  if (total === 0) {
    return (
      <View style={{ flexDirection: 'row', alignItems: 'center', gap: 6, marginTop: 8 }}>
        <View style={{ flex: 1, height: 8, borderRadius: 4, backgroundColor: '#F0F0F5' }} />
        <Text style={{ fontSize: 11, fontWeight: '600', color: COLORS.textSecondary }}>0 votes</Text>
      </View>
    );
  }

  return (
    <View style={{ flexDirection: 'row', alignItems: 'center', gap: 6, marginTop: 8 }}>
      <View style={{ flex: 1, flexDirection: 'row', gap: 3, height: 8 }}>
        <Animated.View style={{
          flex: widthA,
          height: 8,
          borderRadius: 4,
          backgroundColor: COLORS.coral,
        }} />
        <Animated.View style={{
          flex: widthB,
          height: 8,
          borderRadius: 4,
          backgroundColor: COLORS.blue,
        }} />
      </View>
      <Text style={{ fontSize: 11, fontWeight: '700', color: COLORS.textSecondary }}>
        {totalDisplay}
        <Text style={{ fontWeight: '400' }}> votes</Text>
      </Text>
    </View>
  );
}

function PollCard({
  poll,
  index,
  collection,
  onPress,
  onDownloadPress,
}: {
  poll: Poll;
  index: number;
  collection?: Collection;
  onPress: () => void;
  onDownloadPress: () => void;
}) {
  const opacity = useRef(new Animated.Value(0)).current;
  const translateY = useRef(new Animated.Value(16)).current;
  const scale = useRef(new Animated.Value(1)).current;

  React.useEffect(() => {
    Animated.parallel([
      Animated.timing(opacity, { toValue: 1, duration: 350, delay: index * 70, useNativeDriver: true }),
      Animated.timing(translateY, { toValue: 0, duration: 350, delay: index * 70, useNativeDriver: true }),
    ]).start();
  }, []);

  const handlePressIn = () => {
    Animated.spring(scale, { toValue: 0.97, useNativeDriver: true, speed: 50, bounciness: 4 }).start();
  };
  const handlePressOut = () => {
    Animated.spring(scale, { toValue: 1, useNativeDriver: true, speed: 50, bounciness: 4 }).start();
  };

  const countA = poll.counts?.a ?? 0;
  const countB = poll.counts?.b ?? 0;
  const countTotal = poll.counts?.total ?? 0;

  return (
    <Animated.View style={{ opacity, transform: [{ translateY }, { scale }], marginBottom: 12 }}>
      <Pressable
        onPress={onPress}
        onPressIn={handlePressIn}
        onPressOut={handlePressOut}
        style={{
          backgroundColor: COLORS.surface,
          borderRadius: 20,
          padding: 16,
          borderWidth: 1,
          borderColor: poll.is_active ? COLORS.purple : COLORS.border,
          boxShadow: poll.is_active
            ? '0 4px 20px rgba(168,85,247,0.15)'
            : '0 2px 8px rgba(0,0,0,0.05)',
        }}
      >
        <View style={{ flexDirection: 'row', alignItems: 'flex-start', gap: 12 }}>
          {/* Emoji pair */}
          <View style={{
            width: 52,
            height: 52,
            borderRadius: 14,
            backgroundColor: poll.is_active ? COLORS.purpleLight : '#F5F5F5',
            alignItems: 'center',
            justifyContent: 'center',
          }}>
            <Text style={{ fontSize: 22 }}>
              {poll.option_a_emoji}
              {poll.option_b_emoji}
            </Text>
          </View>

          <View style={{ flex: 1 }}>
            <View style={{ flexDirection: 'row', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
              <Text style={{
                fontSize: 16,
                fontWeight: '800',
                color: COLORS.text,
                flex: 1,
              }} numberOfLines={2}>
                {poll.title}
              </Text>
              {poll.is_active && (
                <View style={{
                  flexDirection: 'row',
                  alignItems: 'center',
                  gap: 4,
                  backgroundColor: COLORS.greenLight,
                  paddingHorizontal: 10,
                  paddingVertical: 4,
                  borderRadius: 8,
                }}>
                  <CheckCircle size={12} color={COLORS.green} />
                  <Text style={{ fontSize: 11, fontWeight: '700', color: COLORS.green }}>ACTIVE</Text>
                </View>
              )}
            </View>

            <Text style={{ fontSize: 13, color: COLORS.textSecondary, marginTop: 4, fontWeight: '500' }}>
              {poll.option_a_label}
              <Text style={{ color: COLORS.border }}> vs </Text>
              {poll.option_b_label}
            </Text>

            {/* Folder badge */}
            {collection ? (
              <View style={{
                flexDirection: 'row',
                alignItems: 'center',
                gap: 4,
                alignSelf: 'flex-start',
                backgroundColor: collection.color + '18',
                paddingHorizontal: 8,
                paddingVertical: 3,
                borderRadius: 8,
                marginTop: 6,
              }}>
                <Text style={{ fontSize: 11 }}>{collection.emoji}</Text>
                <Text style={{ fontSize: 11, fontWeight: '700', color: collection.color }}>{collection.name}</Text>
              </View>
            ) : null}

            {/* Mini bar chart */}
            <MiniBarChart countA={countA} countB={countB} total={countTotal} />
          </View>

          {/* Action buttons column */}
          <View style={{ gap: 8 }}>
            {/* Download button */}
            <Pressable
              onPress={(e) => {
                e.stopPropagation();
                onDownloadPress();
              }}
              style={{
                width: 36,
                height: 36,
                borderRadius: 10,
                backgroundColor: '#E0F7F5',
                alignItems: 'center',
                justifyContent: 'center',
              }}
            >
              <Download size={16} color={COLORS.blue} />
            </Pressable>

            {/* Edit button */}
            <View style={{
              width: 36,
              height: 36,
              borderRadius: 10,
              backgroundColor: COLORS.purpleLight,
              alignItems: 'center',
              justifyContent: 'center',
            }}>
              <Pencil size={16} color={COLORS.purple} />
            </View>
          </View>
        </View>
      </Pressable>
    </Animated.View>
  );
}

export default function AdminScreen() {
  const insets = useSafeAreaInsets();
  const router = useRouter();
  const [polls, setPolls] = useState<Poll[]>([]);
  const [collections, setCollections] = useState<Collection[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [modalPoll, setModalPoll] = useState<PollWithCounts | null>(null);
  const [fetchingPollId, setFetchingPollId] = useState<string | null>(null);
  const contentOpacity = useRef(new Animated.Value(0)).current;

  const fetchPolls = useCallback(async () => {
    console.log('[AdminScreen] Fetching polls and collections from', BASE_URL);
    try {
      const [pollsRes, collectionsRes] = await Promise.all([
        fetch(`${BASE_URL}/api/polls`),
        fetch(`${BASE_URL}/api/collections`),
      ]);

      if (!pollsRes.ok) {
        const text = await pollsRes.text();
        console.error('[AdminScreen] Error fetching polls:', pollsRes.status, text);
        setError('Could not load polls');
        return;
      }
      const pollData = await pollsRes.json();
      const pollList: Poll[] = pollData.polls ?? pollData;
      console.log('[AdminScreen] Polls loaded:', pollList.length, 'polls');

      if (collectionsRes.ok) {
        const colData = await collectionsRes.json();
        const colList: Collection[] = colData.collections ?? colData;
        console.log('[AdminScreen] Collections loaded:', colList.length);
        setCollections(colList);
      }

      // Check if counts are already included; if not, fetch individually
      const hasCounts = pollList.length > 0 && pollList[0].counts !== undefined;
      if (!hasCounts && pollList.length > 0) {
        console.log('[AdminScreen] Counts not in list response — fetching individually');
        const withCounts = await Promise.all(
          pollList.map(async (p) => {
            try {
              const r = await fetch(`${BASE_URL}/api/polls/${p.id}`);
              if (!r.ok) return p;
              const d = await r.json();
              return { ...p, counts: d.counts };
            } catch {
              return p;
            }
          })
        );
        setPolls(withCounts);
      } else {
        setPolls(pollList);
      }
      setError(null);
    } catch (e) {
      console.error('[AdminScreen] Network error:', e);
      setError('No internet connection');
    }
  }, []);

  useFocusEffect(
    useCallback(() => {
      console.log('[AdminScreen] Screen focused — refreshing polls');
      setLoading(true);
      fetchPolls().finally(() => {
        setLoading(false);
        Animated.timing(contentOpacity, { toValue: 1, duration: 400, useNativeDriver: true }).start();
      });
    }, [fetchPolls])
  );

  const handleRefresh = useCallback(async () => {
    console.log('[AdminScreen] Pull-to-refresh triggered');
    setRefreshing(true);
    await fetchPolls();
    setRefreshing(false);
  }, [fetchPolls]);

  const handleCreatePoll = () => {
    console.log('[AdminScreen] User pressed create new poll button');
    router.push('/poll-edit');
  };

  const handleEditPoll = (id: string) => {
    console.log('[AdminScreen] User pressed edit poll:', id);
    router.push({ pathname: '/poll-edit', params: { id } });
  };

  const handleDownloadPress = useCallback(async (poll: Poll) => {
    console.log('[AdminScreen] User pressed download for poll:', poll.id, poll.title);
    setFetchingPollId(poll.id);
    try {
      const res = await fetch(`${BASE_URL}/api/polls/${poll.id}`);
      if (!res.ok) {
        const text = await res.text();
        console.error('[AdminScreen] Error fetching poll for download:', res.status, text);
        return;
      }
      const data = await res.json();
      console.log('[AdminScreen] Poll data fetched for download:', data.id, 'counts:', data.counts);
      const pollWithCounts: PollWithCounts = {
        id: data.id,
        title: data.title,
        description: data.description,
        image_url: data.image_url,
        option_a_label: data.option_a_label,
        option_b_label: data.option_b_label,
        option_a_emoji: data.option_a_emoji,
        option_b_emoji: data.option_b_emoji,
        is_active: data.is_active,
        counts: data.counts ?? { a: 0, b: 0, total: 0 },
      };
      setModalPoll(pollWithCounts);
    } catch (e) {
      console.error('[AdminScreen] Network error fetching poll for download:', e);
    } finally {
      setFetchingPollId(null);
    }
  }, []);

  const activeCount = polls.filter(p => p.is_active).length;
  const totalDisplay = polls.length.toString();

  if (loading) {
    return (
      <View style={{ flex: 1, backgroundColor: COLORS.background, justifyContent: 'center', alignItems: 'center' }}>
        <ActivityIndicator size="large" color={COLORS.purple} />
        <Text style={{ marginTop: 16, fontSize: 18, color: COLORS.textSecondary, fontWeight: '600' }}>Loading polls... ⚙️</Text>
      </View>
    );
  }

  if (error) {
    return (
      <View style={{ flex: 1, backgroundColor: COLORS.background, justifyContent: 'center', alignItems: 'center', paddingHorizontal: 32 }}>
        <Text style={{ fontSize: 64 }}>😵</Text>
        <Text style={{ fontSize: 22, fontWeight: '800', color: COLORS.text, marginTop: 16, textAlign: 'center' }}>Oops!</Text>
        <Text style={{ fontSize: 16, color: COLORS.textSecondary, marginTop: 8, textAlign: 'center' }}>{error}</Text>
        <Pressable
          onPress={() => {
            console.log('[AdminScreen] User pressed retry');
            setLoading(true);
            fetchPolls().finally(() => setLoading(false));
          }}
          style={{ marginTop: 24, backgroundColor: COLORS.purple, paddingHorizontal: 32, paddingVertical: 14, borderRadius: 20 }}
        >
          <Text style={{ color: '#FFF', fontSize: 16, fontWeight: '700' }}>Try again</Text>
        </Pressable>
      </View>
    );
  }

  return (
    <Animated.View style={{ flex: 1, opacity: contentOpacity, backgroundColor: COLORS.background }}>
      <ScrollView
        contentInsetAdjustmentBehavior="automatic"
        contentContainerStyle={{
          paddingTop: insets.top + 16,
          paddingBottom: insets.bottom + 120,
          paddingHorizontal: 20,
        }}
        showsVerticalScrollIndicator={false}
        refreshControl={
          <RefreshControl
            refreshing={refreshing}
            onRefresh={handleRefresh}
            tintColor={COLORS.purple}
          />
        }
      >
        {/* Header */}
        <View style={{ flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', marginBottom: 24 }}>
          <View>
            <Text style={{ fontSize: 15, fontWeight: '700', color: COLORS.purple, letterSpacing: 2, textTransform: 'uppercase' }}>
              ⚙️ Admin Panel
            </Text>
            <Text style={{ fontSize: 28, fontWeight: '900', color: COLORS.text, marginTop: 4, letterSpacing: -0.5 }}>
              Manage Polls
            </Text>
          </View>
          <Pressable
            onPress={handleCreatePoll}
            style={{
              width: 48,
              height: 48,
              borderRadius: 16,
              backgroundColor: COLORS.purple,
              alignItems: 'center',
              justifyContent: 'center',
              boxShadow: '0 4px 16px rgba(168,85,247,0.35)',
            }}
          >
            <Plus size={24} color="#FFF" />
          </Pressable>
        </View>

        {/* Stats row */}
        <View style={{ flexDirection: 'row', gap: 12, marginBottom: 24 }}>
          <View style={{
            flex: 1,
            backgroundColor: COLORS.surface,
            borderRadius: 16,
            padding: 16,
            alignItems: 'center',
            boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
            borderWidth: 1,
            borderColor: COLORS.border,
          }}>
            <Text style={{ fontSize: 28, fontWeight: '900', color: COLORS.purple }}>{totalDisplay}</Text>
            <Text style={{ fontSize: 13, color: COLORS.textSecondary, fontWeight: '600', marginTop: 2 }}>Total polls</Text>
          </View>
          <View style={{
            flex: 1,
            backgroundColor: COLORS.surface,
            borderRadius: 16,
            padding: 16,
            alignItems: 'center',
            boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
            borderWidth: 1,
            borderColor: activeCount > 0 ? COLORS.green : COLORS.border,
          }}>
            <Text style={{ fontSize: 28, fontWeight: '900', color: activeCount > 0 ? COLORS.green : COLORS.textSecondary }}>
              {activeCount}
            </Text>
            <Text style={{ fontSize: 13, color: COLORS.textSecondary, fontWeight: '600', marginTop: 2 }}>Active now</Text>
          </View>
        </View>

        {/* Poll list */}
        {polls.length === 0 ? (
          <View style={{
            backgroundColor: COLORS.surface,
            borderRadius: 24,
            padding: 40,
            alignItems: 'center',
            boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
            borderWidth: 1,
            borderColor: COLORS.border,
          }}>
            <Text style={{ fontSize: 56 }}>📋</Text>
            <Text style={{ fontSize: 20, fontWeight: '800', color: COLORS.text, marginTop: 16 }}>No polls yet</Text>
            <Text style={{ fontSize: 15, color: COLORS.textSecondary, marginTop: 8, textAlign: 'center' }}>
              Create your first poll to get kids voting!
            </Text>
            <Pressable
              onPress={handleCreatePoll}
              style={{
                marginTop: 20,
                backgroundColor: COLORS.purple,
                paddingHorizontal: 28,
                paddingVertical: 14,
                borderRadius: 16,
                flexDirection: 'row',
                alignItems: 'center',
                gap: 8,
              }}
            >
              <Plus size={18} color="#FFF" />
              <Text style={{ color: '#FFF', fontSize: 16, fontWeight: '700' }}>Create first poll</Text>
            </Pressable>
          </View>
        ) : (
          polls.map((poll, index) => (
            <View key={poll.id}>
              <PollCard
                poll={poll}
                index={index}
                collection={poll.collection_id ? collections.find(c => c.id === poll.collection_id) : undefined}
                onPress={() => handleEditPoll(poll.id)}
                onDownloadPress={() => handleDownloadPress(poll)}
              />
              {/* Loading overlay for this card while fetching */}
              {fetchingPollId === poll.id && (
                <View style={{
                  position: 'absolute',
                  top: 0, left: 0, right: 0, bottom: 12,
                  borderRadius: 20,
                  backgroundColor: 'rgba(255,255,255,0.75)',
                  alignItems: 'center',
                  justifyContent: 'center',
                }}>
                  <ActivityIndicator size="small" color={COLORS.blue} />
                </View>
              )}
            </View>
          ))
        )}
      </ScrollView>

      {/* Results modal */}
      <ResultsModal
        visible={modalPoll !== null}
        poll={modalPoll}
        onClose={() => {
          console.log('[AdminScreen] Results modal closed');
          setModalPoll(null);
        }}
      />
    </Animated.View>
  );
}
```

**571 lines total.** The file is the Admin screen for managing polls — it fetches polls and collections in parallel, shows a mini animated bar chart per poll card, supports pull-to-refresh, edit/create navigation, and a results modal triggered by the download button.Now I have a clear picture of the admin screen. Let me analyze what the user wants:

